import android.content.Context
import android.content.SharedPreferences

class AuthManager(context: Context) {
    private val sharedPreferences: SharedPreferences = context.getSharedPreferences("AuthPrefs", Context.MODE_PRIVATE)
    private val authTokenKey = "authToken"
    private val userIdKey = "userId"

    fun saveAuthData(authToken: String, userId: String) {
        sharedPreferences.edit().apply {
            putString(authTokenKey, authToken)
            putString(userIdKey, userId)
            apply()
        }
    }

    fun getAuthToken(): String? {
        return sharedPreferences.getString(authTokenKey, null)
    }

    fun getUserId(): String? {
        return sharedPreferences.getString(userIdKey, null)
    }

    fun clearAuthData() {
        sharedPreferences.edit().clear().apply()
    }
}